    37|/** The canonical blocked label surfaced to every owner-gated action. */
    38|export const OWNER_SESSION_REQUIRED_LABEL = 'OWNER_SESSION_REQUIRED' as const;
    39|
    40|/** Why the preflight blocked — one canonical reason per failing branch. */
    41|export type OwnerSessionBlockReason =
    42|  | 'no_supabase_session'
    43|  | 'no_access_token'
    44|  | 'dev_token_blocked_in_production'
    45|  | 'token_not_jwt'
    46|  | 'token_expired'
    47|  | 'owner_email_missing'
    48|  | 'owner_email_not_allowlisted'
    49|  | 'issuer_mismatch';
