    51|/** A single preflight check rendered for diagnostics (never carries the token). */
    52|export type OwnerSessionPreflightCheck = {
    53|  id:
    54|    | 'supabase_session'
    55|    | 'access_token'
    56|    | 'dev_token_block'
    57|    | 'owner_email'
    58|    | 'owner_email_allowlisted'
    59|    | 'issuer_match'
