    82|/** Thrown by `assertOwnerSessionAccessToken` so owner-gated `ownerFetch` helpers can short-circuit. */
    83|export class OwnerSessionRequiredError extends Error {
    84|  readonly label = OWNER_SESSION_REQUIRED_LABEL;
    85|  readonly reason: OwnerSessionBlockReason;
    86|  readonly checks: OwnerSessionPreflightCheck[];
    87|
    88|  constructor(reason: OwnerSessionBlockReason, detail: string, checks: OwnerSessionPreflightCheck[]) {
    89|    super(detail);
    90|    this.name = 'OwnerSessionRequiredError';
    91|    this.reason = reason;
    92|    this.checks = checks;
