    96|type DecodedJwt = { iss?: unknown; exp?: unknown; email?: unknown };
    97|
    98|function decodeJwtPayload(token: string): DecodedJwt | null {
    99|  const segments = token.split('.');
   100|  if (segments.length !== 3) return null;
   101|  try {
   102|    const payloadSegment = segments[1] ?? '';
   103|    const normalized = payloadSegment.replace(/-/g, '+').replace(/_/g, '/');
   104|    const padded = normalized + '='.repeat((4 - (normalized.length % 4)) % 4);
   105|    const decoded =
   106|      typeof atob === 'function' ? atob(padded) : Buffer.from(padded, 'base64').toString('utf8');
   107|    return JSON.parse(decoded) as DecodedJwt;
   108|  } catch {
   109|    return null;
   110|  }
