   120|function getExpectedIssuer(): string | null {
   121|  const frontendSupabaseUrl = resolveSupabaseUrl();
   122|  if (!frontendSupabaseUrl) return null;
   123|  return `${frontendSupabaseUrl.replace(/\/+$/, '')}/auth/v1`;
   124|}
