   126|function issuerMatchesAppProject(issuer: string | null): IssuerMatchResult {
   127|  const frontendSupabaseUrl = resolveSupabaseUrl();
   128|  const expectedIssuer = getExpectedIssuer();
   129|  if (!issuer || !frontendSupabaseUrl) {
   130|    return { matches: null, actualIssuer: issuer ?? null, expectedIssuer, frontendSupabaseUrl };
   131|  }
   132|  const normalizedUrl = frontendSupabaseUrl.replace(/\/+$/, '').toLowerCase();
   133|  const normalizedIssuer = issuer.replace(/\/+$/, '').toLowerCase();
   134|  // Supabase user JWTs typically issue from https://<project>.supabase.co/auth/v1.
   135|  // Accept either an exact match, the project URL as a prefix, or the project ref
   136|  // appearing in the issuer.
   137|  const matches =
   138|    normalizedIssuer === normalizedUrl ||
   139|    normalizedIssuer === `${normalizedUrl}/auth/v1` ||
   140|    normalizedIssuer.startsWith(`${normalizedUrl}/`) ||
   141|    (normalizedIssuer.includes('supabase.co') && normalizedIssuer.includes(normalizedUrl.replace(/^https?:\/\//, '')));
   142|  return { matches, actualIssuer: issuer, expectedIssuer, frontendSupabaseUrl };
