   145|/**
   146| * Aggressively wipe any persisted Supabase session so a stale token from a
   147| * different project can never rehydrate. This is the exact recovery for the
   148| * `issuer_mismatch` branch: a cached session was minted by a different Supabase
   149| * project (old build, local demo, or wrong env) and the frontend now points to
   150| * the production project. Wiping forces a fresh sign-in from the correct URL.
   151| */
   152|async function wipeStaleSupabaseSession(): Promise<void> {
   153|  try {
   154|    const supabase = getIVXSupabaseClient();
   155|    await supabase.auth.signOut().catch(() => {});
   156|  } catch {
   157|    // continue to storage wipe even if signOut throws
   158|  }
   159|
   160|  try {
   161|    const AsyncStorageMod = await import('@react-native-async-storage/async-storage');
   162|    const AsyncStorage = AsyncStorageMod.default ?? AsyncStorageMod;
   163|    const supabaseUrl = resolveSupabaseUrl();
   164|    let projectRef = '';
   165|    try {
   166|      projectRef = new URL(supabaseUrl).hostname.split('.')[0] ?? '';
   167|    } catch {}
   168|    const keysToClear = [
   169|      'supabase.auth.token',
   170|      projectRef ? `sb-${projectRef}-auth-token` : '',
   171|      'ivx-owner-session',
   172|      'ivx_owner_session',
   173|    ].filter(Boolean);
   174|    for (const key of keysToClear) {
   175|      try {
   176|        await AsyncStorage.removeItem(key);
   177|      } catch {
   178|        // ignore per-key removal errors
   179|      }
   180|    }
   181|  } catch {
   182|    // AsyncStorage not available on some runtimes (e.g. SSR); that's fine
   183|  }
   184|
   185|  try {
   186|    if (Platform.OS === 'web' && typeof window !== 'undefined' && window.localStorage) {
   187|      const supabaseUrl = resolveSupabaseUrl();
   188|      let projectRef = '';
   189|      try {
   190|        projectRef = new URL(supabaseUrl).hostname.split('.')[0] ?? '';
   191|      } catch {}
   192|      if (projectRef) {
   193|        try { window.localStorage.removeItem(`sb-${projectRef}-auth-token`); } catch {}
   194|      }
   195|      try { window.localStorage.removeItem('supabase.auth.token'); } catch {}
   196|    }
   197|  } catch {
   198|    // ignore web storage wipe errors
   199|  }
