   202|/**
   203| * Runs the full owner-session preflight. Forces a session refresh by default so a
   204| * soon-to-expire token never reaches the owner route. Returns a structured result;
   205| * the caller owns its action payload, so nothing is lost on a block.
   206| */
   207|export async function runOwnerSessionPreflight(
   208|  options: { forceRefresh?: boolean } = {},
   209|): Promise<OwnerSessionPreflightResult> {
   210|  const forceRefresh = options.forceRefresh ?? true;
   211|  const checks: OwnerSessionPreflightCheck[] = [];
   212|
   213|  // Check 1 — Supabase session exists (read the live session for email + identity).
   214|  let sessionEmail: string | null = null;
   215|  let hasSession = false;
   216|  try {
   217|    const supabase = getIVXSupabaseClient();
   218|    const { data } = await supabase.auth.getSession();
   219|    hasSession = Boolean(data.session?.access_token);
   220|    sessionEmail = data.session?.user?.email ?? null;
   221|  } catch {
   222|    hasSession = false;
   223|  }
   224|  checks.push({
   225|    id: 'supabase_session',
   226|    passed: hasSession,
   227|    detail: hasSession ? 'Supabase session present.' : 'No hydrated Supabase session on this device.',
   228|  });
   229|
   230|  // Check 2 — a real access token resolves (with a forced refresh first).
   231|  let accessToken: string | null = null;
   232|  try {
   233|    accessToken = await getIVXAccessToken({ forceRefresh });
   234|  } catch (error) {
   235|    accessToken = null;
   236|    checks.push({
   237|      id: 'access_token',
   238|      passed: false,
   239|      detail: `Token resolution threw: ${error instanceof Error ? error.message : 'unknown'}.`,
   240|    });
   241|  }
   242|
   243|  if (!accessToken) {
   244|    if (!checks.some((c) => c.id === 'access_token')) {
   245|      checks.push({ id: 'access_token', passed: false, detail: 'No access token after refresh.' });
   246|    }
   247|    const reason: OwnerSessionBlockReason = hasSession ? 'no_access_token' : 'no_supabase_session';
   248|    return {
   249|      ok: false,
   250|      label: OWNER_SESSION_REQUIRED_LABEL,
   251|      reason,
   252|      detail: 'Owner session token unavailable. Sign in as the IVX owner and retry.',
   253|      email: sessionEmail,
   254|      checks,
   255|    };
   256|  }
   257|  checks.push({ id: 'access_token', passed: true, detail: 'Access token resolved.' });
   258|
   259|  // Check 3 — block the synthetic dev-open-access token in production (strict mode).
   260|  const accessConfig = getIVXAccessControlConfig();
   261|  const isDevOpenToken = accessToken === IVX_OPEN_ACCESS_OWNER_TOKEN;
   262|  if (isDevOpenToken && !accessConfig.ownerBypassEnabled) {
   263|    checks.push({
   264|      id: 'dev_token_block',
   265|      passed: false,
   266|      detail: 'Synthetic dev-open-access token blocked from owner route in production.',
   267|    });
   268|    return {
   269|      ok: false,
   270|      label: OWNER_SESSION_REQUIRED_LABEL,
   271|      reason: 'dev_token_blocked_in_production',
   272|      detail: 'Development-only token is not accepted by the owner route. Sign in as the IVX owner and retry.',
   273|      email: sessionEmail,
   274|      checks,
   275|    };
   276|  }
   277|  checks.push({
   278|    id: 'dev_token_block',
   279|    passed: true,
   280|    detail: isDevOpenToken
   281|      ? 'Dev-open-access token allowed in this non-production runtime.'
   282|      : 'Real Supabase JWT (not the dev-open-access token).',
   283|  });
   284|
   285|  // For a real JWT, validate format / expiry / issuer and resolve the email.
   286|  if (!isDevOpenToken) {
   287|    const decoded = decodeJwtPayload(accessToken);
   288|    if (!decoded) {
   289|      checks.push({ id: 'token_validity', passed: false, detail: 'Access token is not a decodable JWT.' });
   290|      return {
   291|        ok: false,
   292|        label: OWNER_SESSION_REQUIRED_LABEL,
   293|        reason: 'token_not_jwt',
   294|        detail: 'The session token is not a valid Supabase JWT. Sign in as the IVX owner and retry.',
   295|        email: sessionEmail,
   296|        checks,
   297|      };
   298|    }
   299|
   300|    // Check 7 — expired session must not POST.
   301|    const exp = typeof decoded.exp === 'number' ? decoded.exp : null;
   302|    const secondsUntilExpiry = exp !== null ? Math.round(exp - Date.now() / 1000) : null;
   303|    if (secondsUntilExpiry !== null && secondsUntilExpiry <= 0) {
   304|      checks.push({
   305|        id: 'token_validity',
   306|        passed: false,
   307|        detail: `Token expired ${Math.abs(secondsUntilExpiry)}s ago.`,
   308|      });
   309|      return {
   310|        ok: false,
   311|        label: OWNER_SESSION_REQUIRED_LABEL,
   312|        reason: 'token_expired',
   313|        detail: 'The session token is expired. Sign in as the IVX owner and retry.',
   314|        email: sessionEmail,
   315|        checks,
   316|      };
   317|    }
   318|    checks.push({
   319|      id: 'token_validity',
   320|      passed: true,
   321|      detail:
   322|        secondsUntilExpiry !== null ? `Token valid (expires in ${secondsUntilExpiry}s).` : 'Token format valid.',
   323|    });
   324|
   325|    // Check 6 — issuer matches the app's Supabase project. This is a HARD block on
   326|    // the client: a token issued by a DIFFERENT Supabase project is a stale cached
   327|    // session from an old build (or a wrong project) and will ALWAYS be rejected by
   328|    // the backend with `issuer_mismatch`. Instead of just blocking, we now actively
   329|    // wipe the stale session and retry once: this handles the common case where the
   330|    // only bad state is the persisted token, and a fresh sign-in will immediately
   331|    // mint a valid token from the current production project.
   332|    const issuer = typeof decoded.iss === 'string' ? decoded.iss : null;
   333|    const issuerMatchResult = issuerMatchesAppProject(issuer);
   334|    const issuerMatch = issuerMatchResult.matches;
   335|    checks.push({
   336|      id: 'issuer_match',
   337|      passed: issuerMatch,
   338|      detail:
   339|        issuerMatch === false
   340|          ? `Token issuer "${issuerMatchResult.actualIssuer ?? 'unknown'}" does not match expected "${issuerMatchResult.expectedIssuer ?? 'unknown'}" (project URL: ${issuerMatchResult.frontendSupabaseUrl ?? 'unset'}). The stale session will be wiped automatically.`
   341|          : issuerMatch === null
   342|            ? 'Issuer match unknown (no app Supabase URL configured).'
   343|            : 'Issuer matches app project.',
   344|    });
   345|
   346|    if (issuerMatch === false) {
   347|      // Auto-clear the stale session so the user cannot keep retrying with the
   348|      // bad token. Then try one refresh: if the refresh token belongs to the
   349|      // same wrong project, this will fail and we'll return the clear re-auth
   350|      // instruction. If it somehow recovers, we continue the normal preflight.
   351|      console.log('[IVXOwnerPreflight] issuer_mismatch detected; wiping stale session:', {
   352|        actualIssuer: issuerMatchResult.actualIssuer,
   353|        expectedIssuer: issuerMatchResult.expectedIssuer,
   354|      });
   355|      await wipeStaleSupabaseSession();
   356|      const recoveredToken = await getIVXAccessToken({ forceRefresh: true });
   357|      if (recoveredToken) {
   358|        const recoveredDecoded = decodeJwtPayload(recoveredToken);
   359|        const recoveredIssuer = typeof recoveredDecoded?.iss === 'string' ? recoveredDecoded.iss : null;
   360|        const recoveredMatch = issuerMatchesAppProject(recoveredIssuer);
   361|        if (recoveredMatch.matches === true) {
   362|          // Fresh token from the correct project: continue preflight with it.
   363|          console.log('[IVXOwnerPreflight] Recovered token matches project after stale-session wipe; continuing preflight.');
   364|          return { ok: true, accessToken: recoveredToken, email: sessionEmail, checks };
   365|        }
   366|        console.log('[IVXOwnerPreflight] Recovered token still mismatched after wipe:', {
   367|          recoveredIssuer,
   368|          expectedIssuer: recoveredMatch.expectedIssuer,
   369|        });
   370|      }
   371|      return {
   372|        ok: false,
   373|        label: OWNER_SESSION_REQUIRED_LABEL,
   374|        reason: 'issuer_mismatch',
   375|        detail: `Owner session issuer mismatch: this device had a cached token from "${issuerMatchResult.actualIssuer ?? 'unknown'}" but the app now expects "${issuerMatchResult.expectedIssuer ?? 'unknown'}". The stale session was cleared automatically. Sign in again with your IVX owner email, then resend. Your message was kept and nothing was sent or changed.`,
   376|        email: sessionEmail,
   377|        checks,
   378|      };
   379|    }
   380|
   381|    // Check 4 — owner email detected (prefer session email, fall back to JWT email).
   382|    const decodedEmail = typeof decoded.email === 'string' ? decoded.email : null;
   383|    const ownerEmail = sessionEmail ?? decodedEmail;
   384|    checks.push({
   385|      id: 'owner_email',
   386|      passed: Boolean(ownerEmail),
   387|      detail: ownerEmail ? 'Owner email detected.' : 'No owner email on the session.',
   388|    });
   389|    void ownerEmail;
   390|
   391|    // Check 5 — owner email allowlisted (soft: the backend allowlist is the source of
   392|    // truth, so a client-side miss is recorded as a warning, not a hard block — the
   393|    // owner route + auth-diagnostic surface the authoritative result).
   394|    const allowlisted = ownerEmail ? isIVXOwnerAllowlistedEmail(ownerEmail) : null;
   395|    checks.push({
   396|      id: 'owner_email_allowlisted',
   397|      passed: allowlisted,
   398|      detail:
   399|        allowlisted === null
   400|          ? 'Owner email allowlist status will be verified by the backend.'
   401|          : allowlisted
   402|            ? 'Owner email is in the device allowlist.'
   403|            : 'Owner email not in the device allowlist; the backend allowlist is authoritative.',
   404|    });
   405|
   406|    return { ok: true, accessToken, email: ownerEmail, checks };
   407|  }
   408|
   409|  // Dev-open-access token accepted in a non-production runtime.
   410|  return { ok: true, accessToken, email: sessionEmail, checks };
   411|}
   412|
   413|/**
   414| * Convenience for owner-gated `ownerFetch` helpers: returns the verified access
   415| * token, or throws `OwnerSessionRequiredError` so the action never POSTs without a
   416| * real owner session and never falls back to /public/chat.
   417| */
   418|export async function assertOwnerSessionAccessToken(
   419|  options: { forceRefresh?: boolean } = {},
   420|): Promise<string> {
   421|  const result = await runOwnerSessionPreflight(options);
   422|  if (!result.ok) {
   423|    throw new OwnerSessionRequiredError(result.reason, result.detail, result.checks);
   424|  }
   425|  return result.accessToken;
   426|}

