import { beforeEach, describe, expect, mock, test } from 'bun:test';

const mockConstants = {
  expoConfig: {
    version: '1.4.3',
    android: { versionCode: 14, package: 'com.ivxholdings.app' },
    ios: { bundleIdentifier: 'com.ivxholdings.app' },
    extra: {
      buildMarker: 'IVX_BUNDLE_2026_07_15_BUILD_14_OWNER_SESSION_STABILIZED',
      buildTimestamp: '2026-07-15T02:55:00.000000+00:00',
      sourceCommitSha: '11872578c4c8bd04ae22d90b8593035475117938',
      watchdogPatchVersion: 'ai-mutation-watchdog-fix-v5-owner-auth-race',
      frontendDeployMarker: 'ivx-frontend-2026-07-15-owner-session-stabilized',
    },
  },
  executionEnvironment: 'standalone',
};

mock.module('expo-constants', () => ({
  default: mockConstants,
}));

describe('IVX build info', () => {
  beforeEach(() => {
    mockConstants.expoConfig.extra = {
      buildMarker: 'IVX_BUNDLE_2026_07_15_BUILD_14_OWNER_SESSION_STABILIZED',
      buildTimestamp: '2026-07-15T02:55:00.000000+00:00',
      sourceCommitSha: '11872578c4c8bd04ae22d90b8593035475117938',
      watchdogPatchVersion: 'ai-mutation-watchdog-fix-v5-owner-auth-race',
      frontendDeployMarker: 'ivx-frontend-2026-07-15-owner-session-stabilized',
    };
  });

  test('reads commit SHA from app.config.ts extra, not from env vars', async () => {
    const { getIVXBuildInfo } = await import('./build-info');
    const info = getIVXBuildInfo();
    expect(info.commitShort).toBe('11872578');
    expect(info.commitFull).toBe('11872578c4c8bd04ae22d90b8593035475117938');
  });

  test('reports production environment for standalone builds', async () => {
    const { getIVXBuildInfo } = await import('./build-info');
    const info = getIVXBuildInfo();
    expect(info.environment).toBe('production');
    expect(info.runtimeKind).toBe('standalone');
  });

  test('reports canonical API base URL', async () => {
    const { getIVXBuildInfo } = await import('./build-info');
    const info = getIVXBuildInfo();
    expect(info.apiBaseUrl).toBe('https://api.ivxholding.com');
  });

  test('build is identified when all required extra values are present', async () => {
    const { getIVXBuildInfo } = await import('./build-info');
    const info = getIVXBuildInfo();
    expect(info.isIdentified).toBe(true);
    expect(info.unidentifiedReason).toBeNull();
  });

  test('assertIVXBuildIdentified does not throw in production with valid values', async () => {
    const { assertIVXBuildIdentified } = await import('./build-info');
    expect(() => assertIVXBuildIdentified()).not.toThrow();
  });

  test('reports unidentified when sourceCommitSha is missing', async () => {
    mockConstants.expoConfig.extra = { ...mockConstants.expoConfig.extra, sourceCommitSha: '' };
    const { getIVXBuildInfo } = await import('./build-info');
    const info = getIVXBuildInfo();
    expect(info.isIdentified).toBe(false);
    expect(info.commitShort).toBe('local');
    expect(info.unidentifiedReason).toContain('Missing sourceCommitSha');
  });
});

